def merge_sorted(a, b):
    result = []
    i = j = 0
    while i < len(a) and j < len(b):
        if a[i] < b[j]:
            result.append(a[i])
        else:
            result.append(b[j])
        i += 1
        j += 1
    return result + a[i:] + b[j:]
